#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n; if(!(cin>>n)) return 0;
    vector<int> nums(n);
    for(int i=0;i<n;++i) cin>>nums[i];
    if(n<=1){ cout<<0; return 0; }
    int jumps=0, current_end=0, farthest=0;
    for(int i=0;i<n-1;++i){
        farthest = max(farthest, i + nums[i]);
        if(i==current_end){
            ++jumps;
            current_end = farthest;
        }
    }
    cout<<jumps;
    return 0;
}
